import{c as n}from"./app.8935f5f1.js";const a={},s=n('<div class="language-java ext-java"><pre class="language-java"><code><span class="token annotation punctuation">@DateTimeFormat</span><span class="token punctuation">(</span>pattern <span class="token operator">=</span> <span class="token string">&quot;yyyy-MM-dd&quot;</span><span class="token punctuation">)</span> <span class="token comment">//入参</span>\n\n\n\n<span class="token annotation punctuation">@JsonFormat</span><span class="token punctuation">(</span>timezone <span class="token operator">=</span> <span class="token string">&quot;GMT+8&quot;</span><span class="token punctuation">,</span> pattern <span class="token operator">=</span> <span class="token string">&quot;yyyy-MM-dd&quot;</span><span class="token punctuation">)</span> <span class="token comment">//出参</span>\n<span class="token annotation punctuation">@RequestBody</span>\n<span class="token comment">// 可以将前台传入的json格式数据自动映射成对象，当如果属性的首字母大写，则会出现不能映射的情况，如：</span>\n<span class="token keyword">private</span> <span class="token class-name">String</span> ICCID<span class="token punctuation">;</span>\n<span class="token comment">// 会出现映射失败的情况解决办法：</span>\n</code></pre></div><ol><li>属性推荐使用小写开头，符合java的开发规范；</li><li>实在要使用大写，可以@jsonProperty(&quot;ICCID&quot;)解决，如：</li></ol><div class="language-java ext-java"><pre class="language-java"><code><span class="token annotation punctuation">@JsonProperty</span><span class="token punctuation">(</span><span class="token string">&quot;ICCID&quot;</span><span class="token punctuation">)</span>\n<span class="token keyword">private</span> <span class="token class-name">String</span> ICCID<span class="token punctuation">;</span>\n\n<span class="token comment">// 实体类大小写</span>\n\n<span class="token annotation punctuation">@JsonProperty</span><span class="token punctuation">(</span><span class="token string">&quot;ID&quot;</span><span class="token punctuation">)</span>\n <span class="token keyword">private</span> <span class="token class-name">String</span> ID<span class="token punctuation">;</span>\n\n    <span class="token annotation punctuation">@JsonIgnore</span>\n    <span class="token keyword">public</span> <span class="token class-name">String</span> <span class="token function">getID</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n         <span class="token keyword">return</span> ID<span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n\n    <span class="token annotation punctuation">@JsonIgnore</span>\n    <span class="token keyword">public</span> <span class="token keyword">void</span> <span class="token function">setID</span><span class="token punctuation">(</span><span class="token class-name">String</span> iD<span class="token punctuation">)</span> <span class="token punctuation">{</span>\n         ID <span class="token operator">=</span> iD<span class="token punctuation">;</span>\n    <span class="token punctuation">}</span>\n</code></pre></div><p>语法：<code>@RequestParam(value=”参数名”,required=”true/false”,defaultValue=””)</code></p><ul><li><p>value：参数名</p></li><li><p>required：是否包含该参数，默认为true，表示该请求路径中必须包含该参数，如果不包含就报错。</p></li><li><p>defaultValue：默认参数值，如果设置了该值，required=true将失效，自动为false,如果没有传该参数，就使用默认值</p></li></ul>',5);a.render=function(n,a){return s};export{a as default};
